    effects: Optional[Tuple[EffectInput, ...]] = Field(default=None, description='The effects of the port')
    default: Optional[Any] = Field(default=None, description='The default value for the port.')
    choices: Optional[Tuple[ChoiceInput, ...]] = Field(default=None, description='The options for the port. This is used for dropdowns and text inputs')
    widget: Optional['ReturnWidgetInput'] = Field(default=None, description='The return widget to use for this port.')
